"body {
  margin: 0;
  overflow: hidden;
  background-color: #050510;
  font-family: 'Courier New', Courier, monospace;
  color: #fff;
  user-select: none;
}

#ui-layer {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
}

#score {
  position: absolute;
  top: 20px;
  left: 20px;
  font-size: 24px;
  color: #0ff;
  text-shadow: 0 0 10px #0ff;
}

#health {
  position: absolute;
  top: 20px;
  right: 20px;
  font-size: 24px;
  color: #f0f;
  text-shadow: 0 0 10px #f0f;
}

.hidden {
  display: none !important;
}

#game-over, #start-screen {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  text-align: center;
}

h1 {
  font-size: 64px;
  margin: 0 0 20px 0;
  color: #fff;
  text-shadow: 0 0 20px #0ff, 0 0 40px #f0f;
  letter-spacing: 5px;
}

p {
  font-size: 24px;
  color: #ccc;
  text-shadow: 0 0 5px #ccc;
}
"

